import React, { useEffect, useState } from 'react'
import {Link, useNavigate } from 'react-router-dom';
import { CButton } from "@coreui/react";
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal } from "src/utils/Common";
import { deleteUserRole, getAllUserRole } from 'src/components/services/RoleApi';
import { tableRoleConstant } from './tableRoleConstant';
import { customStyles } from 'src/utils/tableCustomStyles';
import DataTable from "react-data-table-component";
import authService from 'src/auth/auth.service';

const MySwal = withReactContent(alertPopUp);

const RoleList = () => {
    const [userRoleList ,setUserRoleList] =  useState([]);

    useEffect(()=>{
        getAllUserRoleList();
    },[])

    const handleDeleteRole = async(id) => {
        const response = await deleteUserRole(id);
        if(response?.code === 200){
            getAllUserRoleList();
        }
    }

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDeleteRole(id)
            }
        };
        handleConfirm();
    };

    const getAllUserRoleList = async () =>{
        let response = await getAllUserRole();
        let tableData = [];
        if(response?.code === 200){
            response?.results && response?.results.map((item) => {
                let count = 0;
                let output = [];
                item.permissions && item?.permissions.map((data, index) => {
                  if (index < 1) {
                    output.push(data);
                  } else {
                    count = count + 1;
                  }
                });
                tableData.push({"name": item.name,  "permissions": count === 0 ? output : `${output.join(', ')} +${count}`, "status": item.status, id: item?._id});
            })
        }
        setUserRoleList(tableData);
    }

    return (
        <div className='row'>
            <div className="col2Large">
                <DataTable
                    title="Role"
                    columns={tableRoleConstant(getAllUserRoleList, handleConfirmModal)}
                    data={userRoleList}
                    customStyles={customStyles}
                    //actions={this.actionButton()}
                    pagination
                    paginationPerPage={10}
                    pointerOnHover
                    fixedHeader
                    noContextMenu
                    fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                />
            </div>
            {authService.getPermission("ROLE_CREATE") && <div className='col-sm-12'>
                <Link to={"/role/create"}>
                    <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                        {"+ Create Roles"}
                    </CButton>
                </Link>
            </div>}
        </div>
    )
}

export default RoleList;
